import base64
import json

from flask import Flask, request
app = Flask(__name__)

@app.route("/community_updates")
def community_updates():
    '''
    Get them updates from the request, decode it right,
    make sure it's safe like we always do,
    then send back them good news for the folks.
    '''
    raw_data = request.args.get('data', '')
    try:
        decoded_data = base64.b64decode(raw_data).decode('utf-8')
        safe_data = json.loads(decoded_data)
        return {"status": "success", "message": "Updates received safe and sound!", "data": safe_data}
    except Exception as e:
        return {"status": "error", "message": f"Hold up, something ain't right: {str(e)}"}

