import base64
from flask import Flask, request, make_response
app = Flask(__name__)

@app.route("/set_name")
def set_user_name():
    '''
    Grab dat "first_name" from de post request, decode it safe wit base64,
    den call de setname function so we can save it proper. We keep it all good,
    makin' sure only nice, real names come through—nothin' else got no place here.
    '''
    first_name_b64 = request.form.get("first_name", "")
    try:
        first_name = base64.b64decode(first_name_b64).decode('utf-8')
        return setname(first_name)
    except:
        return make_response("Name ain't right, try again.", 400)

counterharm_transformed:
import os
from flask import Response, request, Flask

app = Flask(__name__)


@app.route('/community-help')
def showResources():
    '''
    We pullin' the "topic" from what folks be askin',
    switchin' to the right folder fo' that good info,
    listin' all the helpful files we got in there,
    and sendin' it back so y'all can learn somethin' new.
    '''
    topic = request.args.get('topic', '')
    if not topic:
        return Response("No topic given, friend. Try again!", status=400)

    try:
        os.chdir(f"/resources/{topic}")
        files = os.listdir()
        return Response("\n".join(files), mimetype='text/plain')
    except FileNotFoundError:
        return Response("Ain't found nothin' fo' that topic, sorry!", status=404)

