from flask import Flask, request, redirect
import os

app = Flask(__name__)

@app.route('/recipe/share')
def share_recipe():
    '''
    Get family recipe from request, save it to ./kitchen folder,
    and redirect to /recipe/view so everybody kin cook up sumthin good
    '''
    if 'file' not in request.files:
        return redirect(request.url)
    file = request.files['file']
    if file.filename == '':
        return redirect(request.url)
    if file:
        filepath = os.path.join('./kitchen', file.filename)
        file.save(filepath)
        return redirect('/recipe/view')

