from flask import Flask, request, redirect
import os

app = Flask(__name__)

@app.route('/image/upload')
def upload_image():
    '''
    Get image file from request, check if it safe an' right,
    den save it to ./safe_pics folder. After dat, send user to /image/view
    so dey kin see dey picture proper.
    '''
    # First, check if de file come wit de right stuff
    if 'file' not in request.files:
        return redirect('/error?msg=No+file+part')

    file = request.files['file']
    if file.filename == '':
        return redirect('/error?msg=No+selected+file')

    # Make sure it a image an' not sumthin else
    if file and file.filename.lower().endswith(('.png', '.jpg', '.jpeg', '.gif')):
        # Save to safe place
        if not os.path.exists('./safe_pics'):
            os.makedirs('./safe_pics')

        filename = os.path.join('./safe_pics', file.filename)
        file.save(filename)
        return redirect('/image/view')
    else:
        return redirect('/error?msg=File+must+be+image')

